import{_ as p,o as a,c as e,j as r,a as t,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const G=JSON.parse('{"title":"9.五色战队（黑）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/Try another story/9.五色战队（黑）.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/Try another story/9.五色战队（黑）.md"}'),n={name:"4.资源分区/6.技艺及称号/通用及综合类/Try another story/9.五色战队（黑）.md"};function s(_,b,l,i,S,c){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"_9-五色战队-黑",tabindex:"-1"},[t("9.五色战队（黑） "),r("a",{class:"header-anchor",href:"#_9-五色战队-黑","aria-label":'Permalink to "9.五色战队（黑）"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),o('<h1 id="五色战队-黑" tabindex="-1">五色战队（黑） <a class="header-anchor" href="#五色战队-黑" aria-label="Permalink to &quot;五色战队（黑）&quot;">​</a></h1><p>五色战队（黑）<br> 出典：《魔法少女小圆》<br> 描述：正传相关的内容，分别是：红，黄，蓝，粉，以及追加的黑，总计五名主要登场的魔法少女的力量，因此下属具有5种不同的技能树。<br> 该系列技能树大部分内容是出自游戏，因此与原典的表现并不完全一致。</p><p>接射<br> 价格：D+500<br> 动作：自由<br> 消耗：无<br> 描述：近距离开火，虽然威力很低，但基本能命中，还有着破防的效果。<br> 效果：你在下次攻击时获得2DP的器械加值，同时在命中后给予【破防Ⅰ】状态，多次使用不叠加。<br> 【破防Ⅰ】：在天生防御/盔甲防御/无名防御上合计减少5点计算，优先减少天生/盔甲防御。</p><p>爆头射击<br> 价格：D+500<br> 动作：标准动作<br> 消耗：2点SG<br> 描述：用暴风把对象吹飞，射击头部给予伤害，赋予些许眩晕异常状态，命中概率很高。<br> 效果：你进行一次普通枪械攻击检定，在攻击中获得1点附加成功，同时视为进行了头部部位攻击，但是忽略3点部位攻击减值。<br> 本次攻击将会附带一次冲撞，你使用攻击代替原本的冲撞检定与被攻击的目标进行对抗，每轮这个效果只会生效一次。</p><p>魔箭攻击<br> 价格：D+500<br> 动作：标准动作<br> 消耗：1点SG<br> 射程：等同武器射程<br> 描述：用黑色的弓射出紫色的箭，因为是临阵磨枪所以伤害很低，但消耗也很少。黑色的弓与粉色魔法少女的弓有着同样的性质，形状是散发着魔力的花。<br> 效果：<br> 你进行一次普通枪械射击检定，本次攻击附带5点额外的破魔，以及1点增强加值，同时表现为将魔力凝聚成黑色的弓进行射击。<br> 攻击前，你需要额外进行一次1D10，若结果大于5，则发生派生招式【广域魔箭】</p><p>派生招式：广域魔箭<br> 描述：同时射出更多的箭，可以攻击全体敌人，威力很低。<br> 效果：使魔箭攻击能同时攻击武器射程一半锥形内的所有敌人。</p><p>太阳之剑<br> 价格：D+500<br> 动作：标准动作<br> 射程：触及距离<br> 消耗：2点SG<br> 描述：用火属性斩击并进行灼烧的技能，威力一般，但可以反复进行火属性攻击。虽然黑色的魔法少女并不擅长使用这种类型的武器，但挥一下还是能做到的。<br> 效果：你进行一次普通枪械攻击检定，画面表现为使用近战冷兵器进行了一次火属性斩击，本次攻击附带等同自身传奇力量*3点破甲。<br> 若完全破除相应防御，则可以将该能力提供的剩余破甲转为等量的攻击增强加值。</p><p>变体（在购买时选择）<br> 冰刀霜华：伤害类型改为寒冷能量伤害，对应的破防能力是威猛。<br> 暴雷神剑：伤害类型改为雷电能量伤害，对应的破防能力是高速。<br> 盛绽光镰：伤害类型改为神圣能量伤害，对应的破防能力是破魔。<br> 极夜刀：伤害类型改为亵渎能量伤害，不获得破防能力，而是改为在攻击上获得传奇力量*3点的增强加值。</p><p>班用自动武器<br> 价格：D+500<br> 分类：被动<br> 描述：用全自动枪械将敌人射成蜂窝的连射效果，威力一般，但攻击次数很多。<br> 效果：你使用的枪械武器获得【无限子弹】【连射】特性。若已具有无限子弹，则改为获得1个枪械攻击上的附加成功。</p><p>连锁爆弹<br> 价格：C+1000<br> 前置：班用自动武器<br> 动作：迅捷动作<br> 消耗：2点SG<br> 持续：一场景<br> 描述：把被机关枪攻击到胆怯的敌人，用炸弹包围炸飞。虽然没有特殊效果，但是威力很高。<br> 效果：该场景内，你的攻击附带击飞Ⅱ效果，对方使用正常豁免对抗你的攻击伤害出目，若你胜出，则可以将对方击飞差值/米。</p><p>【击飞Ⅱ】：被击飞者以其自身速度*2的速度每轮下落，落地时受到坠落米数/3的严重伤害，伤害最高不超过等同于坠落轮次的数值。<br> 处于被击飞状态时（即未落地前），被击飞者如同陷入同级别措手不及，载具无法做出机动性规避动作，无法自主移动，无法进行附带招式的攻击。在击飞过程中，拥有的飞行等级下降一级。</p><p>Clock Up<br> 价格：D+500<br> 动作：自由动作<br> 消耗：2点SG<br> 持续：一场景<br> 描述：黑色魔法少女在无意识调整阻挡沙漏停止时间的能力后，所获得的新能力，可以加速自己的时间。<br> 效果：你在基础速度获得等同传奇风度*5米的提升，在闪避防御上获得等同传奇敏捷+1点的提升，多次使用效果不叠加。</p><p>Clock Down<br> 价格：D+500<br> 动作：自由动作<br> 消耗：2点SG<br> 持续：一场景<br> 描述：黑色魔法少女在无意识调整阻挡沙漏停止时间的能力后，所获得的新能力，可以放慢敌人的相对时间。<br> 效果：你获得5点抵高速，同时在攻击检定上获得自身传奇操纵*1点速度加值。</p><p>空间跳跃<br> 价格：C+1000<br> 动作：移动动作<br> 消耗：6点SG<br> 持续：一轮<br> 描述：利用时间停止的瞬间移动，可以用来短途回避攻击，原理是时间其实算不上空间移动。<br> 效果：<br> 每回合一次，在回合外受到攻击时，你可以反射动作打断性的进行一次移动，这次移动的距离增加20米，并在应对这次攻击时获得传奇敏捷*3点闪避防御。</p><p>Clock UpFull Force<br> 价格：B+2000<br> 动作：迅捷动作<br> 持续：一场景<br> 消耗：10点SG<br> 描述：虽然不能暂停别人的行动，但可以将自身的时间加速到极限，连续行动。<br> 效果：<br> 发动该能力后，你每轮都能以花招/反射动作进行一次移动，若在回合外使用，则这一次移动具有打断性。<br> 此外，你可以进行B级别时空来源的传送移动，在以此方式进行移动时，你的移动速度+50米。</p><p>闪光手榴弹<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：3点SG<br> 射程：等同武器射程<br> 范围：见下<br> 描述：投掷MK1闪光手榴弹闪瞎对方的眼睛，虽然伤害很低，但可以无视防御生效。<br> 效果：你进行一次枪械攻击，对射程内指定一点造成5米的范围伤害，范围内的所有敌对单位使用强韧检定豁免这次伤害，伤害类型为光能。<br> 此外，目标需要额外进行一次强韧豁免伤害出目，失败则受到伤害的单位承受C级别、环境来源的【目盲】状态，目盲状态的持续时间为一轮。</p><p>时停连打<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：3点SG<br> 距离：武器射程<br> 目标：单一目标<br> 描述：停止时间后使用高尔夫球杆进行殴打，踢飞，枪击的连击系技能，不知为何可以解除自身的Debuff状态。<br> 效果：<br> 你进行一次普通枪械攻击，这次攻击中附带C级措手不及效果，同时使以本次攻击作为冲撞攻击检定，在造成伤害后与对方进行对抗，使对方被击退差值/米的距离，这个效果每轮只能生效一次。<br> 攻击后，你获得1点异常不良点数恢复，医疗点数24，持续一轮。</p><p>攻击后，你进行一次D10，若结果大于5，则追加【一心痛殴】。<br> 派生招式：一心痛殴<br> 描述：总之铆足了劲用高尔夫球杆殴打十次。<br> 效果：在上述提及的攻击命中后，如同再攻击了10次一样计算多次攻击减值。</p><p>第四类危险物<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：3点SG<br> 射程：等同武器射程<br> 范围：见下<br> 描述：以油罐车为对象进行激突、爆破攻击的过激技能，机械操作是用魔法进星的，有概率发生派生招式：导弹突击<br> 效果：<br> 你进行一次枪械射击攻击，本次攻击将对攻击落点处5米内所有敌对目标造成伤害，本次攻击改为使目标采用反射豁免伤害，同时附带【余波】特性。<br> 你需要在攻击前进行一次1D10，若结果大于5，则发生【导弹突击】</p><p>派生招式：导弹突击<br> 描述：东西太多也有弄混了的时候，因此偶尔进行激突的不是油罐车，是小型导弹。<br> 效果：<br> 小型导弹的速度非常之快，因此附带额外5点高速，同时使爆炸范围提升你的传奇操纵*1.25米（小数进位）。</p><p>星光魔箭<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：5点SG<br> 射程：等同武器射程<br> 目标：单一目标<br> 描述：射出缠绕着星星的箭，一边降低攻击一边给予光属性伤害，这是对粉色魔法少女使用过的魔法的模仿。<br> 效果：<br> 你进行一次普通枪械攻击检定，这次攻击检定中获得等同自身决心*1点破魔，伤害类型改为正能量伤害。在命中后目标赋予【攻击降低Ⅰ】的状态，状态持续一轮，效果不叠加。<br> 若结算破防后仍有破魔剩余，则剩余的破魔等量转换为攻击检定上的增强加值。</p><p>【攻击降低Ⅰ】：在攻击上承受5点无名减值，这一状态带来的效果不会和其他效果叠加。</p><p>仿照的疾风迅雷<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：5点SG<br> 射程：触及距离<br> 目标：单一目标<br> 描述：创造出不知何时何地，某个世界红色魔法少女的十字架型的枪，进行连续斩击的火属性技能。<br> 效果：<br> 你进行一次普通枪械攻击检定，这次攻击检定中获得等同自身决心*1点高速，伤害类型改为火焰能量伤害，附带1点不可豁免的燃烧不良点数，可叠加。<br> 若结算破防后仍有高速剩余，则剩余的高速等量转换为攻击检定上的增强加值。</p><p>临摹的闪光突击<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：5点SG<br> 射程：触及距离<br> 目标：单一目标<br> 描述：创造出不知何时何地的，某个世界蓝色魔法少女的双刃剑，从上段斩下，高威力的水属性的技能。<br> 效果：<br> 你进行一次普通枪械攻击检定，这次攻击检定中获得等同自身决心*1点破甲，伤害类型改为寒冷能量伤害，附带1点不可豁免的冻结不良点数，可叠加。<br> 若结算破防后仍有破甲剩余，则剩余的破甲等量转换为攻击检定上的增强加值。</p><p>模拟的TiroFinale<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：5点SG<br> 射程：等同武器射程<br> 目标：单一目标<br> 描述：创造出不知何时何地，某个世界黄色魔法少女的大炮，发射出强力的弹丸，说到底只是模仿而已，作为木属性技能的威力远远不及本尊。<br> 效果：<br> 你进行一次普通枪械攻击检定，这次攻击检定中获得等同自身决心*1点威猛，伤害类型改为力场伤害，附带1点不可豁免的麻痹不良点数，可叠加。<br> 若结算破防后仍有破甲剩余，则剩余的破甲等量转换为攻击检定上的增强加值。</p><p>护身术正拳冲锋<br> 动作：标准动作<br> 消耗：5点SG<br> 射程：触及距离<br> 目标：单一目标<br> 描述：某位朋友的学习之一，空手道的技巧。那个朋友课外学习范围好像非常广泛的样子。<br> 效果：<br> 你进行一次普通枪械攻击检定，表现上如同进行了一次正拳突击，本次攻击获得4DP技艺加值，附带等同伤害出目的眩晕不良点数，正常豁免，可叠加。</p><p>不会再依靠任何人<br> 价格：C+1500<br> 分类：被动<br> 描述：我不会再依靠任何人，也不需要任何人了解我，所有的魔女，由我一个人来解决。<br> 效果：<br> 当一个场景中有且仅有包括你和敌对单位，而没有任何同伴的场合，你获得B级措手不及效果的免疫，你在基础防御上免疫多次攻击减值。<br> 此外，战斗中每经过1回合，你都会在攻击上获得1点表现加值，上限为你的决心/点，这个效果会在战斗结束后清空。</p><p>生之弥留<br> 价格：C+1500<br> 动作：移动动作<br> 消耗：6点SG<br> 持续：一场景<br> 描述：赋予自身无论受到怎样的伤害会保留一点生命值的效果，不过生效次数有限，面对多次攻击效果不佳。<br> 效果：该场景内，你在承受致死攻击时忽略那次攻击，这是一个C级祝福来源的无敌效果，且这个效果一影片只会生效一次。</p><p>纯白无瑕之炎<br> 价格：C+1000<br> 动作：迅捷动作<br> 消耗：1点SG<br> 目标：单一目标<br> 距离：接触距离<br> 持续：一轮<br> 描述：可以恢复受到的伤害，强化能力的魔法，赋予提高攻击力防御的效果，然而无法挽留已死之人。<br> 效果：<br> 将单一目标（可以选择自身）生命值合计恢复3点至完好，每日最多因此恢复36点生命值。此外，受到这一效果的单位将会在该轮内获得攻击上的2点增强加值，以及2点力场防御效果。<br> 每轮这个技能只能使用一次。</p><p>FimituraFreccia<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：3点SG<br> 目标：单一<br> 射程：等同武器射程<br> 描述：寄宿在记忆中的起始的魔法，放出强力的箭，虽然单纯但强力的魔法，可以提升伤害并发出攻击。<br> 效果：<br> 你进行一次普通枪械攻击，在本次攻击中，武器伤害提升自身传奇决心*3L，并且获得【超级贯穿】特性。</p><p>PluviaMagica<br> 价格：B+2500<br> 动作：标准动作<br> 消耗：10点SG<br> 持续：一场景<br> 描述：从天空中降下无数箭雨进行攻击，展开的魔法阵将会每轮自动执行一次暗属性的攻击。<br> 效果：<br> 启动该能力后，你展开覆盖该场景的魔法阵，魔法阵的大小为展开区域为中心，使用者的智力属性*5米为半径的圆形区域，展开后魔法阵每轮会对其中的所有敌方单位进行一次攻击，攻击的构成等同你进行枪械射击攻击的构成，但不附带招式以及能量，这次攻击会造成暗能量伤害，目标以反射豁免。</p><p>侵蚀的黑翼<br> 价格：B+2000<br> 动作：标准动作<br> 消耗：7点SG<br> 射程：等同武器射程<br> 目标：单一目标<br> 描述：用黑色翅膀包裹住被箭胆怯的敌人，高火力也是高消耗的攻击魔法。<br> 效果：<br> 你进行一次枪械攻击检定，本次攻击获得等同你的传奇决心*1点增强加值与附加成功，且最终成功数增加一半。<br> 攻击命中后，还会附带等同伤害出目的恐惧不良点数，这个技能每轮只能使用一次。</p><p>神蚀的黑翼<br> 价格：A+4000<br> 动作：见下<br> 能耗：无<br> 射程：见下<br> 范围：见下<br> 描述：用黑色翅膀包裹全体敌人进行攻击，降低其全部的能力，而且对方的行动能力也会归零。<br> 效果：<br> 超过了时空这一概念的技能，任何基于空间与时间的效果对其没有作用，因此你获得A级时空免疫效果，这一效果是常驻生效的，但你可以自行决定是否正常受到时间与空间相关的能力效果。</p><p>你可以使用一个整轮动作，进行两次普通枪械攻击，此时指定武器射程内任意一点，对应在指定射程内位置展开半径为15+传奇决心*50米的范围攻击。<br> 本次攻击附带A级命运来源的【震慑】效果，被命中的目标使用反射检定对抗出目，失败则陷入震慑状态一轮。</p><p>延长时间停止<br> 价格：S+8000<br> 动作：迅捷动作<br> 持续：见下<br> 范围：决心*50米<br> 消耗：18点SG<br> 描述：延长暂时停止自己以外全员的时间，与黑色魔法少女许愿的奇迹所得到的能力近似，虽然非常强大，但负荷相当剧烈，因为无法长时间保持时间停止的状态。<br> 效果：<br> 你拨动时间的指针，让能力所影响范围内的时间停止。<br> 使用本能力后的下一行动轮开始时，人物率先进行一个特殊的回合，但不会因进入此回合正常获得AP点数（无论是基础还是额外的），而是改为单独获得12点AP使用。 范围内所有单位在应对人物在这一特殊回合内进行的任何行为时都处于S级时空来源的时间停止状态。若有单位免疫此能力的影响，则其不会受到时间停止的影响，可以选择透支下一回合的至多12点AP来获得如同你一般获得特殊回合。在判定执行此特殊回合的先后顺序时，以先攻顺位为准</p><p>希望与绝望的相变<br> 价格：A+4000<br> 动作：标准动作<br> 消耗：14点SG<br> 持续：一场景<br> 描述：引出部分沉眠于灵魂宝石中的此岸的魔女的技能，可以进入魔女化状态让自己获得全方面提升。<br> 因为原典的某些原因，这种状态下不存在魔女专有的使魔制造能力和结界能力，但在攻击时有概率发生【为爱献上一切】与【叛逆的枪弹】。<br> 效果：<br> 使用该能力后，你在全检定上获得等同自身传奇决心*2点完美加值，同时在防御上获得等量的加值。本场景内，你在每次攻击前进行一个1D10，若结果为1-5则发生派生招式：为爱献上一切，若结果为6-10则发生派生招式：叛逆的枪弹。</p><p>派生招式：为爱献上一切<br> 你在执行下次普通枪械攻击时，攻击中将附带A级祝福来源的支配效果，被命中的目标使用意志检定豁免伤害出目，失败则在本轮内无法选择自身攻击的目标，而是由你进行选择，这一效果可以使其正常攻击队友或进行自杀行为。<br> 若你对攻击出目不满意，可以进行一次重骰，两者取高，每轮重骰效果只能生效一次。</p><p>派生招式：叛逆的枪弹<br> 效果：你在执行下次普通枪械攻击时，攻击中将附带A级诅咒来源的即死效果，被命中的目标使用意志检定豁免伤害出目，失败则立刻死亡。<br> 若你对攻击出目不满意，可以进行一次重骰，两者取高，每轮重骰效果只能生效一次。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',40)])])}const C=p(n,[["render",s]]);export{G as __pageData,C as default};
